(function($){"use strict";const localized=typeof syncly_cf7_js_data!=="undefined"?syncly_cf7_js_data:{};const GHL_CF7_Admin={init:function(){this.bindEvents();this.loadGHLFields();this.initTagsSelect2()},bindEvents:function(){$("#syncly_enabled").on("change",this.toggleSettings);$(document).on("change",".ghl-checkbox-original",function(){const $label=$(this).closest(".ghl-checkbox");const $span=$label.find(".ghl-checkbox-input");if($(this).is(":checked")){$label.addClass("is-checked");$span.addClass("is-checked")}else{$label.removeClass("is-checked");$span.removeClass("is-checked")}})},toggleSettings:function(){const isEnabled=$(this).is(":checked");$("#syncly_settings_container").toggle(isEnabled)},loadGHLFields:function(){const nonce=localized.nonce||"";if(!nonce){return}
$.ajax({url:ajaxurl,type:"POST",data:{action:"syncly_get_custom_fields",nonce:nonce,},success:function(response){if(response.success&&response.data.fields){GHL_CF7_Admin.populateFieldDropdowns(response.data.fields)}else{GHL_CF7_Admin.showFieldsError()}},error:function(){GHL_CF7_Admin.showFieldsError()},})},populateFieldDropdowns:function(fields){$(".ghl-field-select").each(function(){const $select=$(this);const savedValue=$select.data("saved-value")||"";$select.empty();$.each(fields,function(key,label){const $option=$("<option></option>").attr("value",key).text(label);if(key===savedValue){$option.attr("selected","selected")}
$select.append($option)});if(savedValue){$select.val(savedValue)}});this.checkEmailMapping();$(".ghl-field-select").on("change",this.checkEmailMapping)},showFieldsError:function(){$(".ghl-field-select").each(function(){const $select=$(this);$select.empty();$select.append('<option value="">— Failed to load fields —</option>')})},checkEmailMapping:function(){let hasEmail=!1;$(".ghl-field-select").each(function(){if($(this).val()==="email"){hasEmail=!0;return!1}});$("#syncly_email_notice").toggle(!hasEmail)},initTagsSelect2:function(){const $select=$("#syncly_cf7_tags");if(!$select.length){return}
const tags=localized.tags||[];const savedTags=$select.data("saved-tags")||[];$select.empty();if(tags.length){tags.forEach(function(tag){const tagName=tag.name||tag;const option=new Option(tagName,tagName,!1,!1);$select.append(option)})}
if(savedTags.length){savedTags.forEach(function(tagName){if(!$select[0].querySelector('option[value="'+CSS.escape(tagName)+'"]',)){const option=new Option(tagName,tagName,!1,!1);$select.append(option)}})}
$select.select2({tags:!0,tokenSeparators:[","],placeholder:$select.data("placeholder")||"Select tags...",allowClear:!0,width:"100%",});if(savedTags.length){$select.val(savedTags).trigger("change")}},};$(document).ready(function(){if($(".syncly-cf7-panel").length){GHL_CF7_Admin.init()}})})(jQuery)